// resolveClientIP finds client ip from request data 解析客户端 IP
func resolveClientIP(ctx context.Context, clientID string, clientIP string) (string, error) {
	clientID = strings.TrimSpace(clientID)
	clientIP = strings.TrimSpace(clientIP)
	columns := dao.Clients.Columns()

	if clientIP != "" {
		return clientIP, nil
	}
	if clientID == "" {
		return "", nil
	}

	record, err := dao.Clients.Ctx(ctx).
		Where(columns.ClientId, clientID).
		One()
	if err != nil || !record.IsEmpty() {
		return strings.TrimSpace(gconv.String(record[columns.ClientIp])), err
	}

	record, err = dao.Clients.Ctx(ctx).
		WherePri(gconv.Int64(clientID)).
		One()
	if err != nil || record.IsEmpty() {
		return "", err
	}
	return strings.TrimSpace(gconv.String(record[columns.ClientIp])), nil
}

// findWorkflowIDsByName finds workflow ids by fuzzy name 按名称模糊查询工作流 ID
func findWorkflowIDsByName(ctx context.Context, workflowName string) ([]string, error) {
	columns := dao.AutomaWorkflows.Columns()
	records, err := dao.AutomaWorkflows.Ctx(ctx).
		Fields(columns.AutomaId).
		Where(columns.DeletedAt+" IS NULL").
		Where(columns.Name+" LIKE ?", "%"+workflowName+"%").
		All()
	if err != nil {
		return nil, err
	}

	workflowIDs := make([]string, 0, len(records))
	for _, record := range records {
		workflowID := strings.TrimSpace(gconv.String(record[columns.AutomaId]))
		if workflowID != "" {
			workflowIDs = append(workflowIDs, workflowID)
		}
	}
	return workflowIDs, nil
}

// decodeJSONMap parses json object text for API models 解析 JSON 对象文本
func decodeJSONMap(value string) (model.JSONMap, error) {
	result := model.JSONMap{}
	if value == "" {
		return result, nil
	}
	if err := json.Unmarshal([]byte(value), &result); err != nil {
		return nil, err
	}
	return result, nil
}

// recordTime converts database time values to GoFrame time 转换数据库时间字段
func recordTime(value any) *gtime.Time {
	if value == nil {
		return nil
	}
	t := gconv.Time(value)
	if t.IsZero() {
		return nil
	}
	return gtime.NewFromTime(t)
}
